return items.map(item => {
  const root = item.json || {};
  const envelope = root.body && typeof root.body === 'object' ? root.body : root;
  const headers = root.headers || envelope.headers || {};

  const findDeep = (obj, predicate) => {
    const seen = new Set();
    const stack = [obj];
    while (stack.length) {
      const cur = stack.pop();
      if (!cur || typeof cur !== 'object') continue;
      if (seen.has(cur)) continue;
      seen.add(cur);
      if (predicate(cur)) return cur;
      for (const v of Object.values(cur)) {
        if (v && typeof v === 'object') stack.push(v);
      }
    }
    return null;
  };

  const msg = envelope.message || envelope.data || root.message || root.data || {};
  const eventType =
    msg.type || envelope.type || root.type || envelope.event || root.event || envelope.messageType || root.messageType || null;

  const callObj =
    msg.call || envelope.call || root.call || findDeep(msg, (x) => x.id && (x.startedAt || x.endedAt || x.customer || x.metadata));

  const metadata =
    (callObj && callObj.metadata) || msg.metadata || envelope.metadata || root.metadata ||
    findDeep(msg, (x) => x.num_operacion || x.cedula || x.agente_tipo) || {};

  const customer =
    (callObj && callObj.customer) || msg.customer || envelope.customer || root.customer ||
    findDeep(msg, (x) => x.number && (x.name || x.phoneNumber || x.phone)) || {};

  const startedAt =
    (callObj && callObj.startedAt) || msg.startedAt || envelope.startedAt || root.startedAt || null;
  const endedAt =
    (callObj && callObj.endedAt) || msg.endedAt || envelope.endedAt || root.endedAt || null;

  const headerCallId = headers['x-call-id'] || headers['X-Call-Id'] || headers['x-callid'] || null;
  const callId =
    (callObj && callObj.id) || msg.id || envelope.id || root.id || envelope.callId || root.callId || headerCallId || null;

  item.json = {
    ...root,
    ...envelope,
    ...msg,
    ...(callObj || {}),
    event_type: eventType,
    is_final_event: String(eventType || '').toLowerCase() === 'end-of-call-report' || !!endedAt,
    id_llamada: callId,
    id: callId,
    callId,
    num_operacion: metadata.num_operacion || envelope.num_operacion || root.num_operacion || null,
    cedula: metadata.cedula || envelope.cedula || root.cedula || null,
    agente_tipo: metadata.agente_tipo || envelope.agente_tipo || root.agente_tipo || null,
    telefono_preferido: customer.number || envelope.telefono || root.telefono || null,
    startedAt,
    endedAt,
    phones: 'telefono_preferido',
  };

  return item;
});

return items.map(item => {
  const lead = item.json;
  const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;

  const defaultCC = (lead.system_payload?.CC || '+593').toString();
  const normalizeList = (v) => Array.isArray(v) ? v : String(v || '').split(',');
  const windowFields = normalizeList(lead.phones).map(s => s.trim()).filter(Boolean);
  const phoneFields = windowFields.length ? windowFields : cfg.phoneFields;

  const toE164 = (raw) => {
    let x = String(raw || '').replace(/[^\d+]/g, '').trim();
    if (!x) return '';
    if (x.startsWith('00')) x = '+' + x.slice(2);
    if (!x.startsWith('+')) {
      if (defaultCC === '+593') {
        if (x.startsWith('0')) x = x.slice(1);
        if (/^593\d+$/.test(x)) return '+' + x;
        if (/^\d+$/.test(x)) return '+593' + x;
      } else if (/^\d+$/.test(x)) {
        return defaultCC + x;
      }
    }
    return x;
  };

  const valid = (n) => /^\+\d{7,15}$/.test(n);

  const available = phoneFields
    .map(field => ({ field, raw: lead[field], value: toE164(lead[field]) }))
    .filter(p => p.raw != null && String(p.raw).trim() !== '');

  const unique = [];
  const seen = new Set();
  for (const p of available) {
    if (!p.value || seen.has(p.value)) continue;
    seen.add(p.value);
    unique.push({ ...p, valid: valid(p.value) });
  }

  const idx = Math.max(0, Number(lead.telefono_index ?? 0));
  const selected = unique.slice(idx).find(p => p.valid);

  lead.telefono_actual = selected?.value || '';
  lead.telefono_field = selected?.field || '';
  lead.isOutOfNumbers = !selected;
  lead.hasValidPhones = unique.some(p => p.valid);

  return item;
});

return items.map(item => {
  const root = item.json;
  const cfg = root.cfg || $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
  const lastAgentType = String(root.agente_tipo || root.metadata?.agente_tipo || '').toUpperCase();
  const evtReason = String(root.endedReason || root.event_type || '').toLowerCase();

  // Helper to extract and normalize data
  const extracted = {};
  const processData = (data) => {
    if (!data) return;

    // If it's a string, try to parse it as JSON
    if (typeof data === 'string' && (data.trim().startsWith('{') || data.trim().startsWith('['))) {
        try {
            const parsed = JSON.parse(data);
            processData(parsed);
            return;
        } catch (e) {}
    }

    if (typeof data !== 'object') return;

    for (let [key, val] of Object.entries(data)) {
      if (val === null || val === undefined) continue;

      const k = key.toLowerCase().trim();

      // Map specific keys to expected names
      if (k === 'nomenclatura') extracted.nomenclatura = val;
      else if (k === 'codigo_respuesta' || k === 'codigo') extracted.codigo_respuesta = val;
      else if (k === 'motivo') extracted.motivo = val;
      else if (k === 'fecha_promesa') extracted.fecha_promesa = val;
      else if (k === 'monto_promesa') extracted.monto_promesa = val;
      else if (k === 'canal_promesa' || k === 'canal') extracted.canal = val;
      else if (k === 'fecha_reprogramada' || k === 'fecha_reagenda') extracted.fecha_reagenda = val;
      else if (k === 'es_familiar') extracted.es_familiar = val;
      else if (k === 'telefono_preferido') extracted.telefono_preferido = val;
      else if (k === 'aceptacion') extracted.aceptacion = val;
      else if (k === 'contactoefectivo') extracted.contactoefectivo = val;
      else if (k === 'contactoalo') extracted.contactoalo = val;
      else if (k === 'sentimiento_cliente' || k === 'sentimiento') extracted.sentimiento = val;
      else if (k === 'resumen_llamada' || k === 'resumen') extracted.resumen_llamada = val;

      // If the value itself is a JSON string, process it recursively
      if (typeof val === 'string' && (val.trim().startsWith('{') || val.trim().startsWith('['))) {
        try {
          const parsed = JSON.parse(val);
          processData(parsed);
        } catch (e) {}
      }
    }
  };

  // 1. Search in structuredData
  processData(root.analysis?.structuredData);

  // 2. Search in tool call results from artifact.messages
  const messages = root.artifact?.messages || [];
  messages.forEach(m => {
    if (m.role === 'tool') {
        if (m.name) processData({ [m.name]: m.result });
        else processData(m.result);
    }
  });

  // 3. Search directly in root for any tool-call-like objects (the UUID-keyed objects)
  Object.keys(root).forEach(k => {
    const tool = root[k];
    if (tool && typeof tool === 'object' && tool.name && tool.result !== undefined) {
      processData({ [tool.name]: tool.result });
    }
  });

  // Merge extracted fields into item.json
  Object.assign(item.json, extracted);

  // Policy logic for COBROS failures
  if (lastAgentType === 'COBROS') {
    if (!['customer-ended-call', 'assistant-ended-call', 'assistant-forwarded-call', 'hangup'].includes(evtReason) && evtReason !== '') {
      let rule = cfg.policyCobros.phoneRuleDefault;
      for (const key in cfg.policyCobros.phoneRules) {
        if (key.endsWith('-') && evtReason.startsWith(key)) { rule = cfg.policyCobros.phoneRules[key]; break; }
        if (evtReason === key) { rule = cfg.policyCobros.phoneRules[key]; break; }
      }
      item.json.mapped_by_phonerule = true;
      item.json.status_sugerido = cfg.states.retry;
      return item;
    }
  }

  const isFinalEvent = (String(root.event_type || '').toLowerCase() === 'end-of-call-report');
  if (!isFinalEvent) { item.json.status_sugerido = 'IGNORE'; return item; }

  // Final classification matching
  let successValue = String(item.json.nomenclatura || item.json.codigo_respuesta || '').toUpperCase();
  let match = null;
  if (successValue) {
    match = cfg.catalog.find(c => c.nomenclatura.toUpperCase() === successValue || c.codigo_respuesta.toUpperCase() === successValue);
  }

  const isRetryableNom = cfg.retryNomenclaturas.includes(String(item.json.nomenclatura || '').toUpperCase());
  const isClosureCode = ['COMPAGO', 'COMPAGOASECORP'].includes(item.json.codigo_respuesta);

  if (isRetryableNom && !isClosureCode) item.json.status_sugerido = cfg.states.retry;
  else item.json.status_sugerido = 'FINAL';

  return item;
});

