return items.map(item => {
  const root = item.json || {};
  const cfg = root.cfg || $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
  const lastAgentType = String(root.agente_tipo || root.metadata?.agente_tipo || '').toUpperCase();
  const evtReason = String(root.endedReason || root.event_type || '').toLowerCase();

  const extracted = {};
  const setField = (k, v) => {
    if (v === undefined || v === null) return;
    if (typeof v === 'string' && v.trim() === '') return;
    extracted[k] = v;
  };

  const mapKey = (rawKey) => {
    const k = String(rawKey || '').toLowerCase().trim().replace(/\s+/g, '_');
    if (k === 'nomenclatura') return 'nomenclatura';
    if (k === 'codigo_respuesta' || k === 'codigo') return 'codigo_respuesta';
    if (k === 'motivo') return 'motivo';
    if (k === 'fecha_promesa') return 'fecha_promesa';
    if (k === 'monto_promesa') return 'monto_promesa';
    if (k === 'canal_promesa' || k === 'canal') return 'canal';
    if (k === 'fecha_reprogramada' || k === 'fecha_reagenda') return 'fecha_reagenda';
    if (k === 'es_familiar') return 'es_familiar';
    if (k === 'telefono_preferido') return 'telefono_preferido';
    if (k === 'aceptacion') return 'aceptacion';
    if (k === 'contactoefectivo') return 'contactoefectivo';
    if (k === 'contactoalo') return 'contactoalo';
    if (k === 'sentimiento_cliente' || k === 'sentimiento') return 'sentimiento';
    if (k === 'resumen_llamada' || k === 'resumen') return 'resumen_llamada';
    return null;
  };

  const processData = (data) => {
    if (data == null) return;
    if (typeof data === 'string') {
      const s = data.trim();
      if ((s.startsWith('{') && s.endsWith('}')) || (s.startsWith('[') && s.endsWith(']'))) {
        try { processData(JSON.parse(s)); } catch (_) {}
      }
      return;
    }
    if (Array.isArray(data)) return data.forEach(processData);
    if (typeof data !== 'object') return;

    if (Object.prototype.hasOwnProperty.call(data, 'name') && Object.prototype.hasOwnProperty.call(data, 'result')) {
      const mapped = mapKey(data.name);
      if (mapped) setField(mapped, data.result);
      processData(data.result);
    }

    for (const [key, val] of Object.entries(data)) {
      const mapped = mapKey(key);
      if (mapped) setField(mapped, val);
      if (val && typeof val === 'object') processData(val);
      if (typeof val === 'string') {
        const s = val.trim();
        if ((s.startsWith('{') && s.endsWith('}')) || (s.startsWith('[') && s.endsWith(']'))) {
          try { processData(JSON.parse(s)); } catch (_) {}
        }
      }
    }
  };

  processData(root.structuredOutputs);
  processData(root.artifact?.structuredOutputs);
  processData(root.message?.artifact?.structuredOutputs);
  processData(root.analysis?.structuredData);
  (root.artifact?.messages || []).forEach(m => {
    if (m && m.role === 'tool') {
      if (m.name) processData({ name: m.name, result: m.result });
      processData(m.result);
    }
  });

  Object.assign(item.json, extracted);

  const raw = String(item.json.num_operacion ?? item.json.metadata?.num_operacion ?? '').trim();
  if (!raw) {
    item.json.query = "SELECT 'skip_update_sin_num_operacion' AS status;";
    item.json.status_sugerido = item.json.status_sugerido || 'IGNORE';
    return item;
  }

  const isFinalEvent = String(item.json.event_type || '').toLowerCase() === 'end-of-call-report';
  const idLlamadaRaw = String(item.json.id_llamada || item.json.callId || item.json.id || '').trim();
  const hasIdLlamada = idLlamadaRaw !== '';
  const hasCierre = !!(item.json.endedAt || item.json.endedReason || item.json.hora_fin_llamada || item.json.ultimo_resultado_llamada || item.json.endedcall);
  item.json.es_llamada_real = hasIdLlamada && hasCierre;
  if (!isFinalEvent) {
    item.json.query = "SELECT 'skip_non_final_event' AS status;";
    item.json.status_sugerido = 'IGNORE';
    return item;
  }

  if (lastAgentType === 'COBROS' && !['customer-ended-call', 'assistant-ended-call', 'assistant-forwarded-call', 'hangup'].includes(evtReason) && evtReason !== '') {
    item.json.mapped_by_phonerule = true;
    item.json.status_sugerido = cfg.states.retry;
  }

  const isRetryableNom = cfg.retryNomenclaturas.includes(String(item.json.nomenclatura || '').toUpperCase());
  const isClosureCode = ['COMPAGO', 'COMPAGOASECORP'].includes(String(item.json.codigo_respuesta || ''));
  if (!item.json.status_sugerido) {
    item.json.status_sugerido = (isRetryableNom && !isClosureCode) ? cfg.states.retry : 'FINAL';
  }

  const numOperacion = raw.replace(/'/g, "''");
  const estadoFinalFlujo = item.json.status_sugerido === 'FINAL' ? cfg.states.done : cfg.states.retry;
  const fechaReagendaRaw = item.json.reintentar_iso || item.json.fecha_reagenda || null;
  const fechaReagendaSql = (fechaReagendaRaw == null || String(fechaReagendaRaw).trim() === '')
    ? `NOW() + INTERVAL '${(cfg.runtime.timeOffsetMinutes||0) + 30} minutes'`
    : `'${String(fechaReagendaRaw).replace(/'/g, "''")}'::timestamptz`;

  const fechaGestionRaw = item.json.hora_fin_llamada || item.json.fecha_gestion || item.json.endedAt || item.json.endedcall || null;
  const fechaGestionSql = (fechaGestionRaw == null || String(fechaGestionRaw).trim() === '')
    ? `NOW() + INTERVAL '${cfg.runtime.timeOffsetMinutes||0} minutes'`
    : `'${String(fechaGestionRaw).replace(/'/g, "''")}'::timestamptz`;

  const telRaw = item.json.numero_telefono || item.json.telefono_preferido || item.json.telefono_actual || null;
  const telSql = (telRaw == null || String(telRaw).trim() === '') ? 'NULL' : `'${String(telRaw).replace(/'/g, "''")}'`;

  const contactoAloSi = String(item.json.contactoalo || '').trim().toLowerCase() === 'si';
  const estado = contactoAloSi ? cfg.states.done : estadoFinalFlujo;
  const setFechaReagenda = estado === cfg.states.retry ? fechaReagendaSql : 'NULL';
  const endRes = String(item.json.endedReason || item.json.event_type || '').replace(/'/g, "''");

  item.json.query = `UPDATE ${cfg.db.schema}.${cfg.db.table}
          SET estado_flujo = '${estado}',
              fecha_reagenda = ${setFechaReagenda},
              fecha_ultima_llamada = ${fechaGestionSql},
              ultimo_resultado_llamada = '${endRes}',
              telefono_preferido = CASE WHEN ${contactoAloSi ? 'TRUE' : 'FALSE'} AND ${telSql} IS NOT NULL THEN ${telSql} ELSE telefono_preferido END,
              telefono_index = CASE WHEN ${contactoAloSi ? 'TRUE' : 'FALSE'} THEN 0 ELSE telefono_index END,
              updated_at = NOW()
          WHERE num_operacion = '${numOperacion}'
          RETURNING num_operacion, estado_flujo, fecha_reagenda, 'updated_by_cierre' AS status, ${item.json.es_llamada_real ? 'TRUE' : 'FALSE'} AS es_llamada_real;`;

  return item;
});
